class Database:
    def __init__(self, path: str):
        self.path = path
        self._lock = threading.Lock()
        self._init_db()

    def _connect(self):
        conn = sqlite3.connect(self.path, check_same_thread=False)
        conn.row_factory = sqlite3.Row
        return conn

    def _init_db(self):
        with self._connect() as conn:
            conn.execute("""
                CREATE TABLE IF NOT EXISTS images (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    filename TEXT NOT NULL,
                    filepath TEXT NOT NULL,
                    created_at TEXT NOT NULL
                )
            """)
            conn.execute("""
                CREATE TABLE IF NOT EXISTS annotations (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    image_id INTEGER NOT NULL,
                    annotator_id TEXT NOT NULL,
                    label TEXT NOT NULL,
                    created_at TEXT NOT NULL,
                    UNIQUE(image_id, annotator_id),
                    FOREIGN KEY(image_id) REFERENCES images(id)
                )
            """)
            conn.commit()

    def add_image(self, filename: str, filepath: str) -> int:
        with self._lock, self._connect() as conn:
            cur = conn.execute(
                "INSERT INTO images (filename, filepath, created_at) VALUES (?, ?, ?)",
                (filename, filepath, datetime.utcnow().isoformat())
            )
            conn.commit()
            return cur.lastrowid

    def get_image(self, image_id: int) -> Optional[Dict]:
        with self._connect() as conn:
            row = conn.execute("SELECT * FROM images WHERE id = ?", (image_id,)).fetchone()
            return dict(row) if row else None

    def list_images(self) -> List[Dict]:
        with self._connect() as conn:
            rows = conn.execute("SELECT * FROM images ORDER BY id DESC").fetchall()
            return [dict(r) for r in rows]

    def add_annotation(self, image_id: int, annotator_id: str, label: str):
        with self._lock, self._connect() as conn:
            conn.execute("""
                INSERT INTO annotations (image_id, annotator_id, label, created_at)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(image_id, annotator_id) DO UPDATE SET
                    label=excluded.label,
                    created_at=excluded.created_at
            """, (image_id, annotator_id, label, datetime.utcnow().isoformat()))
            conn.commit()

    def get_annotations_for_image(self, image_id: int) -> List[Dict]:
        with self._connect() as conn:
            rows = conn.execute(
                "SELECT * FROM annotations WHERE image_id = ? ORDER BY created_at ASC",
                (image_id,)
            ).fetchall()
            return [dict(r) for r in rows]

    def get_all_annotations(self) -> List[Dict]:
        with self._connect() as conn:
            rows = conn.execute("SELECT * FROM annotations").fetchall()
            return [dict(r) for r in rows]

    def get_aggregated_labels(self) -> List[Dict]:
        with self._connect() as conn:
            image_rows = conn.execute("SELECT * FROM images ORDER BY id ASC").fetchall()
            results = []
            for image_row in image_rows:
                image_id = image_row["id"]
                ann_rows = conn.execute(
                    "SELECT label, COUNT(*) as cnt FROM annotations WHERE image_id = ? GROUP BY label ORDER BY cnt DESC, label ASC",
                    (image_id,)
                ).fetchall()
                if not ann_rows:
                    continue
                majority_label = ann_rows[0]["label"]
                vote_count = ann_rows[0]["cnt"]
                total_votes = sum(r["cnt"] for r in ann_rows)
                label_distribution = {r["label"]: r["cnt"] for r in ann_rows}
                results.append({
                    "image_id": image_id,
                    "filename": image_row["filename"],
                    "filepath": image_row["filepath"],
                    "majority_label": majority_label,
                    "vote_count": vote_count,
                    "total_votes": total_votes,
                    "distribution": label_distribution
                })
            return results

    def get_label_set(self) -> List[str]:
        with self._connect() as conn:
            rows = conn.execute("SELECT DISTINCT label FROM annotations ORDER BY label ASC").fetchall()
            return [r["label"] for r in rows]


db = Database(DB_PATH)
app = Flask(__name__)


class ImageLabelDataset(Dataset):
    def __init__(self, samples: List[Dict], label_to_idx: Dict[str, int], image_size: int = 64):
        self.samples = samples
        self.label_to_idx = label_to_idx
        self.image_size = image_size

    def __len__(self):
        return len(self.samples)

    def _load_image(self, path: str):
        img = Image.open(path).convert("RGB")
        img = img.resize((self.image_size, self.image_size))
        arr = np.asarray(img, dtype=np.float32) / 255.0
        arr = np.transpose(arr, (2, 0, 1))
        return torch.tensor(arr, dtype=torch.float32)

    def __getitem__(self, idx):
        sample = self.samples[idx]
        x = self._load_image(sample["filepath"])
        y = self.label_to_idx[sample["majority_label"]]
        return x, torch.tensor(y, dtype=torch.long)


class SimpleCNN(nn.Module):
    def __init__(self, num_classes: int):
        super().__init__()
        self.net = nn.Sequential(
            nn.Conv2d(3, 16, kernel_size=3, padding=1),
            nn.ReLU(),
            nn.MaxPool2d(2),

            nn.Conv2d(16, 32, kernel_size=3, padding=1),
            nn.ReLU(),
            nn.MaxPool2d(2),

            nn.Conv2d(32, 64, kernel_size=3, padding=1),
            nn.ReLU(),
            nn.MaxPool2d(2),

            nn.Flatten(),
            nn.Linear(64 * 8 * 8, 128),
            nn.ReLU(),
            nn.Linear(128, num_classes)
        )

    def forward(self, x):
        return self.net(x)


def train_model(epochs: int = 5, batch_size: int = 16, lr: float = 1e-3):
    aggregated = db.get_aggregated_labels()
    if not aggregated:
        raise ValueError("No aggregated labeled data available for training.")

    label_set = sorted(list({item["majority_label"] for item in aggregated}))
    if len(label_set) < 2:
        raise ValueError("At least two classes are required for training.")

    label_to_idx = {label: i for i, label in enumerate(label_set)}
    dataset = ImageLabelDataset(aggregated, label_to_idx)
    loader = DataLoader(dataset, batch_size=batch_size, shuffle=True)

    model = SimpleCNN(num_classes=len(label_set)).to(DEVICE)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=lr)

    model.train()
    history = []
    for epoch in range(epochs):
        total_loss = 0.0
        total = 0
        correct = 0
        for x, y in loader:
            x = x.to(DEVICE)
            y = y.to(DEVICE)

            optimizer.zero_grad()
            logits = model(x)
            loss = criterion(logits, y)
            loss.backward()
            optimizer.step()

            total_loss += loss.item() * x.size(0)
            preds = torch.argmax(logits, dim=1)
            total += y.size(0)
            correct += (preds == y).sum().item()

        epoch_loss = total_loss / max(total, 1)
        epoch_acc = correct / max(total, 1)
        history.append({
            "epoch": epoch + 1,
            "loss": epoch_loss,
            "accuracy": epoch_acc
        })

    payload = {
        "model_state_dict": model.state_dict(),
        "label_to_idx": label_to_idx,
        "idx_to_label": {i: l for l, i in label_to_idx.items()},
        "image_size": 64
    }
    torch.save(payload, MODEL_PATH)
    return history, len(dataset), label_set


def load_trained_model():
    if not os.path.exists(MODEL_PATH):
        raise FileNotFoundError("Model file not found.")
    payload = torch.load(MODEL_PATH, map_location=DEVICE)
    idx_to_label = payload["idx_to_label"]
    num_classes = len(idx_to_label)
    model = SimpleCNN(num_classes=num_classes).to(DEVICE)
    model.load_state_dict(payload["model_state_dict"])
    model.eval()
    return model, payload


def preprocess_image_bytes(image_bytes: bytes, image_size: int):
    img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    img = img.resize((image_size, image_size))
    arr = np.asarray(img, dtype=np.float32) / 255.0
    arr = np.transpose(arr, (2, 0, 1))
    tensor = torch.tensor(arr, dtype=torch.float32).unsqueeze(0)
    return tensor.to(DEVICE)


@app.route("/images", methods=["POST"])
def upload_image():
    if "image" not in request.files:
        return jsonify({"error": "Missing image file under form field 'image'"}), 400

    file = request.files["image"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400

    timestamp = datetime.utcnow().strftime("%Y%m%d%H%M%S%f")
    safe_name = os.path.basename(file.filename)
    stored_name = f"{timestamp}_{safe_name}"
    path = os.path.join(IMAGE_DIR, stored_name)
    file.save(path)

    image_id = db.add_image(filename=file.filename, filepath=path)
    return jsonify({
        "image_id": image_id,
        "filename": file.filename,
        "stored_path": path
    }), 201


