@app.route("/annotations", methods=["POST"])
def submit_annotation():
    data = request.get_json(silent=True)
    if not data:
        return jsonify({"error": "Expected JSON body"}), 400

    image_id = data.get("image_id")
    annotator_id = data.get("annotator_id")
    label = data.get("label")

    if image_id is None or not annotator_id or not label:
        return jsonify({"error": "Fields 'image_id', 'annotator_id', and 'label' are required"}), 400

    image = db.get_image(int(image_id))
    if not image:
        return jsonify({"error": "Image not found"}), 404

    db.add_annotation(int(image_id), str(annotator_id), str(label))
    annotations = db.get_annotations_for_image(int(image_id))

    counts = {}
    for ann in annotations:
        counts[ann["label"]] = counts.get(ann["label"], 0) + 1
    majority_label = sorted(counts.items(), key=lambda x: (-x[1], x[0]))[0][0] if counts else None

    return jsonify({
        "status": "ok",
        "image_id": int(image_id),
        "annotator_id": str(annotator_id),
        "label": str(label),
        "majority_label": majority_label,
        "distribution": counts
    }), 201


