@app.route("/train", methods=["POST"])
def train():
    data = request.get_json(silent=True) or {}
    epochs = int(data.get("epochs", 5))
    batch_size = int(data.get("batch_size", 16))
    lr = float(data.get("lr", 1e-3))

    try:
        history, dataset_size, labels = train_model(epochs=epochs, batch_size=batch_size, lr=lr)
        return jsonify({
            "status": "trained",
            "model_path": MODEL_PATH,
            "dataset_size": dataset_size,
            "labels": labels,
            "history": history,
            "validation": None
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/predict", methods=["POST"])
def predict():
    if "image" not in request.files:
        return jsonify({"error": "Missing image file under form field 'image'"}), 400

    try:
        model, payload = load_trained_model()
    except Exception as e:
        return jsonify({"error": str(e)}), 400

    image_bytes = request.files["image"].read()
    x = preprocess_image_bytes(image_bytes, payload["image_size"])

    with torch.no_grad():
        logits = model(x)
        probs = torch.softmax(logits, dim=1)[0].cpu().numpy()

    idx_to_label = payload["idx_to_label"]
    pred_idx = int(np.argmax(probs))
    pred_label = idx_to_label[pred_idx] if pred_idx in idx_to_label else idx_to_label[str(pred_idx)]

    prob_map = {}
    for i, p in enumerate(probs.tolist()):
        label = idx_to_label[i] if i in idx_to_label else idx_to_label[str(i)]
        prob_map[label] = p

    return jsonify({
        "predicted_label": pred_label,
        "probabilities": prob_map
    })


